import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import ProductCard from '../components/ProductCard';
import './Shop.css';

const Shop = () => {
  const [products, setProducts] = useState([]);
  const [category, setCategory] = useState('All');
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const stored = localStorage.getItem('products');
    const data = stored ? JSON.parse(stored) : [];
    setProducts(data);

    const params = new URLSearchParams(location.search);
    const cat = params.get('category');
    if (cat) setCategory(cat);
    else setCategory('All');
  }, [location]);

  const handleCategoryChange = (e) => {
    const newCat = e.target.value;
    setCategory(newCat);
    navigate(`/shop?category=${newCat}`);
  };

  const filtered = category === 'All' ? products : products.filter(p => p.category === category);

  return (
    <div className="shop-page">
      <div className="shop-header">
        <h2>{category === 'All' ? 'All Products' : `${category} Collection`}</h2>
        <select value={category} onChange={handleCategoryChange} className="shop-category-filter">
          <option value="All">All</option>
          <option value="Plants">Plants</option>
          <option value="Flowers">Flowers</option>
          <option value="Decor">Decor</option>
          <option value="Pots">Pots</option>
        </select>
      </div>
      <div className="shop-grid">
        {filtered.length ? filtered.map((p, idx) => (
          <ProductCard key={idx} product={p} onEdit={() => {}} onDelete={() => {}} />
        )) : <p className="no-products">No products available in this category.</p>}
      </div>
    </div>
  );
};

export default Shop;
